mapper.select:
SELECT ar.*,
       COALESCE(NULLIF(TRIM(a.title), ''), a.name) AS activity_title,
       a.type AS activity_type,
       s.name AS student_name,
       t.name AS teacher_name
FROM activity_registration ar
LEFT JOIN activity a ON ar.activity_id = a.id
LEFT JOIN sys_user s ON ar.student_id = s.id
LEFT JOIN sys_user t ON ar.teacher_id = t.id

    AND ar.activity_id = #{param.activityId}
    AND a.type = #{param.activityType}
    AND ar.student_id = #{param.studentId}
    AND ar.teacher_id = #{param.teacherId}
    AND ar.status = #{param.status}

ORDER BY ar.create_time DESC
